#include <iostream>

int addInts(int a, int b)
{
    std::cerr << "[addInts] a=" << a << " b=" << b << '\n';
    int result = a + b;
    std::cerr << "[addInts] returning " << result << '\n';
    return result;
}

int main()
{
    int a = 0;
    int b = 0;
    std::cin >> a >> b;
    std::cout << "Sum: " << addInts(a, b) << '\n';
    return 0;
}

